import React from 'react';
import { VerdictType } from '../types';
import { CheckCircle2, XCircle, AlertTriangle, HelpCircle, AlertCircle, Loader2 } from 'lucide-react';

interface Props {
  verdict: VerdictType;
  className?: string;
}

export const VerdictBadge: React.FC<Props> = ({ verdict, className = '' }) => {
  switch (verdict) {
    case VerdictType.TRUE:
      return (
        <div className={`inline-flex items-center gap-1.5 bg-green-900/30 text-green-400 border border-green-800 px-3 py-1 rounded-full font-semibold text-xs ${className}`}>
          <CheckCircle2 className="w-4 h-4" />
          Verified True
        </div>
      );
    case VerdictType.FALSE:
      return (
        <div className={`inline-flex items-center gap-1.5 bg-red-900/30 text-red-400 border border-red-800 px-3 py-1 rounded-full font-semibold text-xs ${className}`}>
          <XCircle className="w-4 h-4" />
          False News
        </div>
      );
    case VerdictType.MISLEADING:
      return (
        <div className={`inline-flex items-center gap-1.5 bg-amber-900/30 text-amber-400 border border-amber-800 px-3 py-1 rounded-full font-semibold text-xs ${className}`}>
          <AlertTriangle className="w-4 h-4" />
          Misleading
        </div>
      );
    case VerdictType.UNVERIFIED:
      return (
        <div className={`inline-flex items-center gap-1.5 bg-slate-800 text-slate-300 border border-slate-600 px-3 py-1 rounded-full font-semibold text-xs ${className}`}>
          <HelpCircle className="w-4 h-4" />
          Needs Review
        </div>
      );
    default:
      // If the verdict is unknown but we aren't explicitly loading (parent controls loading), show Unknown.
      return (
        <div className={`inline-flex items-center gap-1.5 bg-slate-800 text-slate-400 border border-slate-700 px-3 py-1 rounded-full font-medium text-xs ${className}`}>
          <AlertCircle className="w-4 h-4" />
          Unknown Status
        </div>
      );
  }
};

import { GoogleGenAI } from "@google/genai";
import { FactCheckResult, VerdictType, Source, TickerItem } from "../types";
import { db } from "./db";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- UTILS ---

/**
 * Retries a promise-returning function multiple times with a delay.
 * Solves "Connection Error" flakiness.
 */
const retryOperation = async <T>(operation: () => Promise<T>, retries = 2, delay = 800): Promise<T> => {
  for (let i = 0; i < retries; i++) {
    try {
      return await operation();
    } catch (error) {
      if (i === retries - 1) throw error;
      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }
  throw new Error("Operation failed after retries");
};

/**
 * INDESTRUCTIBLE JSON CLEANER
 * Handles: Markdown, Newlines, Mixed content
 */
const cleanJsonString = (text: string): string => {
  if (!text) return "";

  // 1. Strip Markdown
  let clean = text.replace(/```json/g, "").replace(/```/g, "");

  // 2. Find the outer-most JSON structure (Array OR Object)
  const firstOpenBrace = clean.indexOf('{');
  const firstOpenBracket = clean.indexOf('[');

  // If we find an Object first (or only an Object)
  if (firstOpenBrace !== -1 && (firstOpenBracket === -1 || firstOpenBrace < firstOpenBracket)) {
      const lastCloseBrace = clean.lastIndexOf('}');
      if (lastCloseBrace !== -1) clean = clean.substring(firstOpenBrace, lastCloseBrace + 1);
  } 
  // If we find an Array first
  else if (firstOpenBracket !== -1) {
      const lastCloseBracket = clean.lastIndexOf(']');
      if (lastCloseBracket !== -1) clean = clean.substring(firstOpenBracket, lastCloseBracket + 1);
  }

  // 3. Cleanup characters that break JSON.parse
  clean = clean.replace(/[\r\n\t]+/g, " ");

  return clean.trim();
};

const getNewsImage = (category: string, keyword: string): string => {
