/**
 * Retries a promise-returning function.
 */
const retryOperation = async <T>(operation: () => Promise<T>, retries = 1, delay = 500): Promise<T> => {
  for (let i = 0; i < retries; i++) {
    try {
      return await operation();
    } catch (error) {
      if (i === retries - 1) throw error;
      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }
  throw new Error("Operation failed after retries");
};

/**
 * INDESTRUCTIBLE JSON CLEANER
 * Necessary because when using Google Search Tools, we cannot use Strict Schema Mode easily.
 * This function extracts JSON from the AI's text response, even if it adds extra commentary.
 */
const cleanJsonString = (text: string): string => {
  if (!text) return "";

  // 1. Strip Markdown code blocks
  let clean = text.replace(/```json/g, "").replace(/```/g, "");

  // 2. Find the outer-most JSON structure (Array OR Object)
  const firstOpenBrace = clean.indexOf('{');
  const firstOpenBracket = clean.indexOf('[');

  if (firstOpenBrace !== -1 && (firstOpenBracket === -1 || firstOpenBrace < firstOpenBracket)) {
      const lastCloseBrace = clean.lastIndexOf('}');
      if (lastCloseBrace !== -1) clean = clean.substring(firstOpenBrace, lastCloseBrace + 1);
  } else if (firstOpenBracket !== -1) {
      const lastCloseBracket = clean.lastIndexOf(']');
      if (lastCloseBracket !== -1) clean = clean.substring(firstOpenBracket, lastCloseBracket + 1);
  }

  // 3. Cleanup characters that break JSON.parse
  clean = clean.replace(/[\r\n\t]+/g, " ");
  return clean.trim();
};

