export const fetchRealTopNews = async (): Promise<TickerItem[]> => {
    const model = "gemini-2.5-flash";
    const prompt = `Search the latest global news. Return a JSON array of 5 breaking headlines. 
    Format: [{"headline":"Text","verdict":"TRUE","source":"Name"}]`;

    try {
        const response = await retryOperation<GenerateContentResponse>(() => ai.models.generateContent({
            model,
            contents: { parts: [{ text: prompt }] },
            config: { 
                tools: [{ googleSearch: {} }], // ENABLE INTERNET SEARCH
                maxOutputTokens: 500, 
                temperature: 0.1,
            }
        }));

        const cleanedText = cleanJsonString(response.text || "[]");
