      const cached = db.getTicker();
      if (cached && cached.length > 0) {
          setTickerItems(cached);
      }

      // 2. Network Fetch in Background
      try {
        const news = await fetchRealTopNews();
        if (news && news.length > 0) {
            setTickerItems(news);
        }
      } catch(e) {
          console.error("Ticker update failed", e);
      }
  };

  const loadContent = async (force = false) => {
    // If we have no data at all, show loading spinner
    const cached = db.getTrending();
    if (cached.length === 0) {
        setLoadingTrending(true);
    }

    // Refresh local checks from DB
    const local = db.getLocalChecks();
    setLocalChecks(local);

    try {
        // If force is true (stale cache or user clicked button), this triggers API
        const trending = await fetchTrendingDebunks(force);
        setTrendingChecks(trending);
    } catch (e) {
        console.error(e);
    } finally {
        setLoadingTrending(false);
    }
  };

  const handleVote = (checkId: string, option: 'trueVotes' | 'falseVotes' | 'misleadingVotes') => {
    castVote(checkId, option);
    const updateList = (list: FactCheckResult[]) => list.map(item => {
        if (item.id === checkId) {
            return {
                ...item,
                communityPoll: {
                    ...item.communityPoll,
                    [option]: item.communityPoll[option] + 1,
                    total: item.communityPoll.total + 1
                }
            };
        }
        return item;
    });
    setTrendingChecks(prev => updateList(prev));
    setLocalChecks(prev => updateList(prev));
  };

  const handleFeedback = (id: string) => {
      alert("Thank you for your feedback. We have flagged this analysis for review by our team.");
  };

  const handleShare = async (item: FactCheckResult) => {
    const shareText = `FactPulse Verification: ${item.headline || item.claim}\nVerdict: ${item.verdict}\n\n${item.explanation}`;
    const shareUrl = item.sources[0]?.uri || window.location.href;

    if (navigator.share) {
        try {
            await navigator.share({
                title: 'FactPulse Verification',
                text: shareText,
                url: shareUrl
            });
        } catch (err) {
            console.log('User cancelled or share failed', err);
        }
    } else {
        // Fallback to X (Twitter) intent
        const twitterUrl = `https://twitter.com/intent/tweet?text=${encodeURIComponent(shareText.substring(0, 200) + '...')}&url=${encodeURIComponent(shareUrl)}`;
        window.open(twitterUrl, '_blank');
    }
  };

  const feedItems = [...localChecks, ...trendingChecks];

  return (
    <div className="max-w-7xl mx-auto px-4 py-6">

      {/* Real-Time Intelligence Bar */}
      <div className="bg-slate-900 border-y border-slate-800 mb-8 overflow-hidden py-3 relative flex items-center shadow-soft">
         <div className="bg-red-600 text-white text-[10px] font-bold px-3 py-1 ml-4 rounded z-10 flex items-center gap-2 whitespace-nowrap shadow-sm">
             <span className="w-1.5 h-1.5 rounded-full bg-white animate-pulse"></span>
             LIVE INTEL
         </div>
         <div className="flex-1 overflow-hidden ml-4">
             <div className="animate-marquee whitespace-nowrap flex items-center gap-12 text-sm font-medium text-slate-300">
                 {tickerItems.length > 0 ? tickerItems.map((item, i) => (
                     <span key={i} className="flex items-center gap-2">
                        {item.verdict === 'TRUE' ? (
                            <CheckCircle2 className="w-4 h-4 text-green-500" />
                        ) : (
                            <XCircle className="w-4 h-4 text-red-500" />
                        )}
                        <span className={item.verdict === 'TRUE' ? 'text-green-400 font-bold text-xs uppercase' : 'text-red-400 font-bold text-xs uppercase'}>
                            {item.verdict}
                        </span>
                        <span className="text-white">{item.headline}</span>
                        <span className="text-xs text-slate-500 border-l border-slate-700 pl-2">{item.source}</span>
                     </span>
                 )) : (
                     <span>Scanning global verified news sources...</span>
                 )}
             </div>
         </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">

        {/* Main Feed (Left) */}
        <div className="lg:col-span-3 space-y-6">
            <div className="flex items-center justify-between mb-4">
                <h2 className="text-2xl font-bold text-white tracking-tight">Top Stories</h2>
                <button 
                    onClick={() => loadContent(true)}
                    className="flex items-center gap-2 text-xs font-bold text-primary-400 hover:text-primary-300 transition-colors bg-slate-900 px-3 py-2 rounded-lg border border-slate-800"
                >
                    <RefreshCw className={`w-3 h-3 ${loadingTrending ? 'animate-spin' : ''}`} />
                    Update Feed
                </button>
            </div>

            {loadingTrending && feedItems.length === 0 ? (
                <div className="space-y-6">
                    {[1, 2].map(i => (
                        <div key={i} className="bg-slate-900 rounded-xl h-80 animate-pulse border border-slate-800"></div>
                    ))}
                </div>
            ) : (
                feedItems.map((item) => (
                    <div key={item.id} className="bg-slate-900 rounded-xl overflow-hidden shadow-card border border-slate-800 hover:border-slate-700 transition-all group">

                        <div className="grid grid-cols-1 md:grid-cols-3">
                            {/* Image Section */}
                            <div className="md:col-span-1 h-48 md:h-auto relative overflow-hidden bg-slate-950">
                                {item.imageUrl ? (
                                    <img 
                                        src={item.imageUrl} 
                                        alt={item.headline} 
                                        className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                                    />
                                ) : (
                                    <div className="w-full h-full flex items-center justify-center text-slate-700">
                                        <Activity className="w-12 h-12" />
                                    </div>
                                )}
                                <div className="absolute top-2 left-2">
                                    <VerdictBadge verdict={item.verdict} className="shadow-lg backdrop-blur-sm" />
                                </div>
                            </div>

                            {/* Content Section */}
                            <div className="md:col-span-2 p-6 flex flex-col justify-between">
                                <div>
                                    <div className="flex items-center gap-2 text-xs text-slate-500 mb-2">
                                        <span className="font-bold text-primary-500 uppercase">{item.author}</span>
                                        <span>•</span>
                                        <span>{new Date(item.timestamp).toLocaleDateString()}</span>
                                    </div>

                                    <h3 className="text-xl font-bold text-white mb-3 leading-snug">
                                        {item.headline || item.claim}
                                    </h3>

                                    <p className="text-slate-400 text-sm line-clamp-3 mb-4 leading-relaxed">
                                        {item.explanation}
                                    </p>
                                </div>

                                <div>
                                    {/* Action Bar */}
                                    <div className="flex flex-wrap items-center justify-between gap-4 pt-4 border-t border-slate-800/50">
                                        <div className="flex-1 min-w-[180px]">
                                             <PollWidget 
                                                checkId={item.id} 
                                                stats={item.communityPoll} 
                                                onVote={handleVote} 
                                                userVotedOption={user?.votes?.[item.id]} 
                                             />
                                        </div>
                                        <div className="flex items-center gap-3">
                                            {item.sources[0] && (
                                                <a href={item.sources[0].uri} target="_blank" rel="noopener noreferrer" className="text-xs font-bold text-slate-400 hover:text-white flex items-center gap-1 transition-colors">
                                                    Read Source <ChevronRight className="w-3 h-3" />
                                                </a>
                                            )}

                                            <button 
                                                onClick={() => handleShare(item)}
                                                className="text-slate-500 hover:text-primary-400 p-1.5 rounded-md hover:bg-primary-900/10 transition-colors"
                                                title="Share this verification"
                                            >
                                                <Share2 className="w-3 h-3" />
                                            </button>

                                            <button 
                                                onClick={() => handleFeedback(item.id)}
                                                className="text-slate-500 hover:text-amber-500 p-1.5 rounded-md hover:bg-amber-900/10 transition-colors"
                                                title="Report inaccuracy"
                                            >
                                                <Flag className="w-3 h-3" />
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                ))
            )}

            {feedItems.length === 0 && !loadingTrending && (
                <div className="text-center py-10 bg-slate-900 rounded-xl border border-slate-800">
                    <p className="text-slate-400 mb-2">Failed to load trending news.</p>
                    <button onClick={() => loadContent(true)} className="text-primary-500 hover:underline text-sm">Try Again</button>
                </div>
            )}
        </div>

        {/* Sidebar (Right) */}
        <div className="lg:col-span-1 space-y-6">
             {/* Live Activity */}
             <div className="bg-slate-900 rounded-xl p-5 border border-slate-800 shadow-card">
                 <div className="flex items-center gap-2 mb-4">
                     <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                     <h3 className="font-bold text-white text-sm">Community Pulse</h3>
                 </div>
                 <div className="space-y-4">
                     {activities.map((act, i) => (
                         <div key={i} className="flex items-start gap-3 text-sm pb-3 border-b border-slate-800/50 last:border-0 last:pb-0">
                             <div className="w-8 h-8 rounded-full bg-slate-800 flex items-center justify-center text-[10px] font-bold text-slate-400 border border-slate-700 shrink-0">
                                 {act.name.substring(0,2)}
                             </div>
                             <div>
                                 <p className="text-slate-300 leading-tight text-xs">
                                     <span className="font-bold text-white">{act.name}</span> {act.action}
                                 </p>
                                 <p className="text-[10px] text-slate-500 mt-1">{act.time}</p>
                             </div>
                         </div>
                     ))}
                 </div>
             </div>

             {/* Online Users */}
             <div className="bg-gradient-to-br from-primary-900/20 to-slate-900 rounded-xl p-6 border border-primary-900/30">
                 <h3 className="font-bold text-white text-sm mb-1">Active Agents</h3>
                 <div className="flex items-end gap-2">
                    <span className="text-4xl font-bold text-primary-400">{activeUsersCount.toLocaleString()}</span>
                    <span className="text-xs text-primary-500/70 mb-1.5 font-bold">ONLINE</span>
                 </div>
                 <p className="text-xs text-slate-400 mt-3 leading-relaxed">
                     Join thousands of fact-checkers keeping the internet safe.
                 </p>
                 <Link to="/verify" className="mt-4 block w-full py-2.5 bg-primary-600 hover:bg-primary-500 text-white text-xs font-bold text-center rounded-lg transition-colors shadow-lg shadow-primary-900/20">
                     Start Verifying
                 </Link>
             </div>
        </div>

      </div>
    </div>
  );
};
